// SPDX-License-Identifier: MIT
pragma solidity ^0.8.26;

contract CommitRevealLottery {
    uint256 public constant COMMIT_DURATION = 60;
    uint256 public constant REVEAL_DURATION = 60;
    uint256 public constant ENTRY_FEE = 0.1 ether;

    uint256 public immutable startTime;
    uint256 public combinedEntropy;
    bool public finalized;

    mapping(address => bytes32) public commits;
    mapping(address => bool) public revealed;
    address[] public players;

    event Winner(address winner, uint256 amount);

    constructor() {
        startTime = block.timestamp;
    }

    function commit(bytes32 commitHash) external payable {
        require([[SLOT commit_active]], "Commit phase over");
        require(msg.value == ENTRY_FEE, "Wrong entry fee");
        require(commits[msg.sender] == bytes32(0), "Already committed");

        commits[msg.sender] = commitHash;
        players.push(msg.sender);
    }

    function reveal(uint256 secret) external {
        uint256 revealStart = startTime + COMMIT_DURATION;
        require(block.timestamp >= revealStart, "Reveal phase not started");
        require(block.timestamp < revealStart + REVEAL_DURATION, "Reveal phase over");
        require(commits[msg.sender] != bytes32(0), "No commit found");
        require(!revealed[msg.sender], "Already revealed");

        bytes32 computedHash = [[SLOT commit_hash]];
        require(computedHash == commits[msg.sender], "Invalid secret");

        revealed[msg.sender] = true;
        [[SLOT entropy_xor]]
    }

    function pickWinner() external {
        uint256 revealEnd = startTime + COMMIT_DURATION + REVEAL_DURATION;
        require(block.timestamp >= revealEnd, "Lottery not finished");
        require(!finalized, "Already finalized");

        address[] memory revealedPlayers = new address[](players.length);
        uint256 count = 0;
        for (uint256 i = 0; i < players.length; i++) {
            if (revealed[players[i]]) {
                revealedPlayers[count] = players[i];
                count++;
            }
        }

        require(count > 0, "No players revealed");

        address winner = revealedPlayers[[[SLOT winner_idx]]];
        finalized = true;

        uint256 prize = address(this).balance;
        emit Winner(winner, prize);
        payable(winner).transfer(prize);
    }
}
